mapper.select:
SELECT t.review_id, t.source_type, t.title, t.description, t.status, t.submitter_id, su.real_name AS submitter_name, t.reviewer_id, ru.real_name AS reviewer_name, t.reason, t.created_at, t.reviewed_at FROM content_review_task t LEFT JOIN user su ON su.user_id = t.submitter_id LEFT JOIN user ru ON ru.user_id = t.reviewer_id
AND t.source_type = #{query.sourceType}
AND t.status = #{query.status}
AND ( t.title LIKE CONCAT('%', #{query.keyword}, '%') OR su.real_name LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY t.created_at DESC

mapper.update:
UPDATE content_review_file
SET final_url = #{finalUrl},
    updated_at = NOW()
WHERE review_id = #{reviewId}
  AND file_id = #{fileId}
